const express = require('express');
const router = express.Router({ mergeParams: true });
const { getTasksByStatus, updateTaskStatus } = require('./service');

router.get('/', async (req, res) => {
  const tasks = await getTasksByStatus(req.params.projectId, req.query.status);
  if (!tasks) return sendError(res, 404, 'E002', 'Tasks not found');
  res.json({ tasks });
});

router.patch('/:taskId', async (req, res) => {
  const status = req.body.status;
  if (!['todo', 'done'].includes(status)) return sendError(res, 400, 'E003', 'Invalid task status');
  const updatedTask = await updateTaskStatus(req.params.projectId, req.params.taskId, status);
  res.json({ task: updatedTask });
});

exports.router = router;

const express = require('express');
const app = express();
const projectsRouter = require('./modules/projects/routes');
const membersRouter = require('./modules/members/routes');
const tasksRouter = require('./modules/tasks/routes');
const commentsRouter = require('./modules/comments/routes');
app.use(express.json());
app.get('/health', (req, res) => { res.json({ ok: true }); });
app.use('/projects', projectsRouter);
app.use('/projects/:projectId/members', membersRouter);
app.use('/projects/:projectId/tasks', tasksRouter);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRouter);
module.exports = app;

